import React from "react";

export default function StartTest() {
  return (
    <div style={{ padding: "40px", textAlign: "center" }}>
      <h1>MBTI ტესტი</h1>
      <p>უპასუხე კითხვებს გულწრფელად, რომ გაიგო შენი ფსიქოტიპი</p>
      <button
        style={{
          padding: "12px 30px",
          fontSize: "18px",
          borderRadius: "8px",
          cursor: "pointer"
        }}
      >
        დაწყება
      </button>
    </div>
  );
}
